-- PostgreSQL upsert script generated from products.csv
-- Product rows: 368

BEGIN;

CREATE SEQUENCE IF NOT EXISTS product_id_seq;

CREATE TABLE IF NOT EXISTS product (
  id BIGINT PRIMARY KEY DEFAULT nextval('product_id_seq'),
  category TEXT NOT NULL,
  subcategory TEXT NOT NULL,
  product_name TEXT NOT NULL,
  image_path TEXT,
  design_description TEXT,
  size TEXT
);

ALTER TABLE product ADD COLUMN IF NOT EXISTS id BIGINT;
ALTER TABLE product ALTER COLUMN id SET DEFAULT nextval('product_id_seq');
UPDATE product SET id = nextval('product_id_seq') WHERE id IS NULL;
SELECT setval('product_id_seq', COALESCE((SELECT MAX(id) FROM product), 0) + 1, false);
ALTER SEQUENCE product_id_seq OWNED BY product.id;
ALTER TABLE product ALTER COLUMN id SET NOT NULL;

DO $$
DECLARE
  pk_name TEXT;
  pk_columns TEXT[];
BEGIN
  SELECT c.conname, array_agg(a.attname ORDER BY k.ord)
    INTO pk_name, pk_columns
  FROM pg_constraint c
  JOIN unnest(c.conkey) WITH ORDINALITY AS k(attnum, ord) ON TRUE
  JOIN pg_attribute a ON a.attrelid = c.conrelid AND a.attnum = k.attnum
  WHERE c.conrelid = 'product'::regclass
    AND c.contype = 'p'
  GROUP BY c.conname;

  IF pk_name IS NOT NULL AND pk_columns <> ARRAY['id'] THEN
    EXECUTE format('ALTER TABLE product DROP CONSTRAINT %I', pk_name);
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conrelid = 'product'::regclass
      AND contype = 'p'
  ) THEN
    ALTER TABLE product ADD CONSTRAINT product_pkey PRIMARY KEY (id);
  END IF;
END $$;

CREATE UNIQUE INDEX IF NOT EXISTS product_category_subcategory_name_uidx
  ON product (category, subcategory, product_name);


ON CONFLICT (category, subcategory, product_name) DO UPDATE SET
  image_path = EXCLUDED.image_path,
  design_description = EXCLUDED.design_description,
  size = EXCLUDED.size;

COMMIT;
